const profiles = [
  "https://www.linkedin.com/company/n8n-io/posts/",
  "https://www.linkedin.com/company/make-com/posts/",
  "https://www.linkedin.com/in/tibo-louis-viger/posts/",
  "https://www.linkedin.com/in/guillaume-moubeche/posts/",
  "https://www.linkedin.com/in/arnaud-belinga/posts/"
];
return [{ json: { actorInput: { startUrls: profiles.map(url => ({ url })), maxPostsPerProfile: 10, proxyConfiguration: { useApifyProxy: true } } } }];

const raw = $input.first().json;
const posts = Array.isArray(raw) ? raw : (raw.items || raw.data || []);

const filtered = posts
  .filter(post => {
    const likes    = post.likes || post.numLikes || post.reactionCount || 0;
    const comments = post.comments || post.numComments || post.commentCount || 0;
    return (likes + comments) >= 100;
  })
  .slice(0, 10)
  .map(post => ({ json: {
    hasData: true,
    url:      post.url || post.postUrl || '',
    author:   post.authorName || post.author?.name || 'Inconnu',
    content:  (post.text || post.content || '').substring(0, 2000),
    likes:    post.likes || post.numLikes || post.reactionCount || 0,
    comments: post.comments || post.numComments || post.commentCount || 0,
    shares:   post.shares || post.numShares || 0,
    postedAt: post.postedAt || new Date().toISOString()
  }}));

if (filtered.length === 0) return [{ json: { hasData: false } }];
return filtered;

const ollamaText = $input.first().json.response || '';
let analysis = {};
try {
  const m = ollamaText.match(/\{[\s\S]*\}/);
  if (m) analysis = JSON.parse(m[0]);
} catch(e) { analysis = { hook: 'N/A', rehook: 'N/A', payoff: 'N/A', cta: 'N/A', hook_type: 'autre', format: 'Moyen', theme: 'automation', score_viral: 5 }; }

const postData = $('Loop: Analyze Posts').first().json;

return [{ json: {
  id: `viral_${Date.now()}_${Math.random().toString(36).substr(2,6)}`,
  url:       postData.url || '',
  author:    postData.author || '',
  content:   postData.content || '',
  likes:     postData.likes || 0,
  comments:  postData.comments || 0,
  shares:    postData.shares || 0,
  postedAt:  postData.postedAt || '',
  hook:      analysis.hook || '',
  rehook:    analysis.rehook || '',
  payoff:    analysis.payoff || '',
  cta:       analysis.cta || '',
  hookType:  analysis.hook_type || 'autre',
  format:    analysis.format || 'Moyen',
  theme:     analysis.theme || 'automation',
  scoreViral: Number(analysis.score_viral) || 5,
  scrapedAt: new Date().toISOString()
} }];

const posts = $input.all();

const topPosts = posts
  .sort((a, b) => (Number(b.json.ScoreViral) || 0) - (Number(a.json.ScoreViral) || 0))
  .slice(0, 8)
  .map(p => ({
    hook:     p.json.Hook || '',
    hookType: p.json.HookType || 'autre',
    payoff:   p.json.Payoff || '',
    cta:      p.json.CTA || '',
    theme:    p.json.Theme || 'automation'
  }));

const hookCounts = {};
topPosts.forEach(p => { hookCounts[p.hookType] = (hookCounts[p.hookType] || 0) + 1; });
const bestHook = Object.entries(hookCounts).sort((a, b) => b[1] - a[1])[0]?.[0] || 'confession';

const examples = topPosts.slice(0, 4)
  .map((p, i) => `Exemple ${i+1} [${p.hookType}/${p.theme}]:
Hook: ${p.hook}
Valeur: ${p.payoff}
CTA: ${p.cta}`)
  .join('

');

const prompt = `Tu es un copywriter expert LinkedIn spécialisé en automatisation no-code.
Ton persona : Freelance français, expert n8n/Make.com, tu aides les PME à automatiser sans coder.
Ton ton : direct, authentique, pas corporate. Tu parles de vraies expériences client.

PATTERNS VIRAUX DÉTECTÉS (dominant: "${bestHook}"):
${examples}

CRÉE 3 POSTS LINKEDIN distincts, EN FRANÇAIS :
1. POST "confession" : erreur ou apprentissage lié à l'automatisation
2. POST "stats" : chiffre surprenant + solution n8n
3. POST "question" : douleur commune en PME + réponse automatisée

CHAQUE POST doit :
- Commencer par un hook puissant (max 2 lignes)
- Utiliser Hook → Rehook → Valeur → CTA
- Mentionner un résultat concret
- Terminer par un CTA fort
- Faire 800-1200 caractères
- Être authentique, pas marketo-bullshit

Réponds UNIQUEMENT avec ce JSON valide :
{
  "posts": [
    { "type": "confession", "content": "[texte complet]", "hook": "[première ligne]", "image_prompt": "[prompt anglais Flux/Midjourney]" },
    { "type": "stats", "content": "[texte complet]", "hook": "[première ligne]", "image_prompt": "[prompt anglais]" },
    { "type": "question", "content": "[texte complet]", "hook": "[première ligne]", "image_prompt": "[prompt anglais]" }
  ]
}`;

return [{ json: { prompt, bestHook, postCount: topPosts.length } }];

const ollamaText = $input.first().json.response || '';
let parsed = { posts: [] };
try {
  const m = ollamaText.match(/\{[\s\S]*"posts"[\s\S]*\}/);
  if (m) parsed = JSON.parse(m[0]);
} catch(e) {
  parsed = { posts: [{ type: 'draft', content: ollamaText.substring(0, 1200), hook: 'Draft auto-généré', image_prompt: 'Clean automation workflow diagram, modern, professional' }] };
}

if (!parsed.posts?.length) return [{ json: { error: 'No posts', raw: ollamaText.substring(0, 300) } }];

return parsed.posts.map((post, idx) => ({
  json: {
    id:          `post_${Date.now()}_${idx}_${Math.random().toString(36).substr(2,5)}`,
    type:        post.type || 'draft',
    content:     post.content || '',
    hook:        post.hook || '',
    imagePrompt: post.image_prompt || 'Professional automation workspace, clean, modern',
    index:       idx + 1,
    totalPosts:  parsed.posts.length,
    createdAt:   new Date().toISOString()
  }
}));

